={{ 
  (() => {
    const obj = $json.objective;
    const actions = $json.actions || [];

    // Este diccionario es el "Traductor"
    const mapping = {
      // Si el objetivo es Ventas -> Busca Compras
      'OUTCOME_SALES': 'web_in_store_purchase', 

      // Si el objetivo es Mensajes -> Busca Conversaciones nuevas
      'OUTCOME_MESSAGES': 'onsite_conversion.total_messaging_connection',

      // Si el objetivo es Tráfico -> Busca Clics en el enlace
      'OUTCOME_TRAFFIC': 'link_click',

      // Si el objetivo es Leads (Clientes potenciales) -> Busca Clientes potenciales
      'OUTCOME_LEADS': 'lead',

      // Si el objetivo es Interacción (Engagement) -> Busca Interacciones con el post
      'OUTCOME_ENGAGEMENT': 'post_engagement'
    };

    const targetAction = mapping[obj];

    // Buscamos en la lista de acciones de esa campaña específica
    const result = actions.find(a => a.action_type === targetAction);

    // Si lo encuentra, devuelve el número. Si no existe esa acción ese día, devuelve 0.
    return result ? Number(result.value) : 0;
  })()
}}

={{ 
  (() => {
    const nombre = $json.campaign_name;
    const gastoTotal = Number($json.spend);

    if (nombre.includes('[P100]')) {
      return gastoTotal.toFixed(2);
    } else {
      // Si no tiene la etiqueta [P100], se asume 50/50
      return (gastoTotal * 0.50).toFixed(2);
    }
  })()
}}

