={{ 
  (() => {
    // 1. Buscamos el resultado (usando la lógica que ya conocemos)
    const obj = $json.objective;
    const actions = $json.actions || [];
    const mapping = {
      'OUTCOME_SALES': 'web_in_store_purchase',
      'OUTCOME_MESSAGES': 'onsite_conversion.total_messaging_connection',
      'OUTCOME_LEADS': 'lead',
      'OUTCOME_TRAFFIC': 'link_click'
    };

    const action = actions.find(a => a.action_type === mapping[obj]);
    const numResultados = action ? Number(action.value) : 0;
    const gasto = Number($json.spend) || 0;

    // 2. Calculamos el costo
    // Si hubo resultados, divide gasto/resultados. Si no, el costo es el gasto total.
    return numResultados > 0 ? (gasto / numResultados).toFixed(2) : gasto.toFixed(2);
  })()
}}

